input.command:
curl -s -X POST \
  -H "Authorization: Bearer $GITHUB_TOKEN" \
  -H "Content-Type: application/json" \
  "https://api.github.com/graphql" \
  -d '{
    "query": "query($owner:String!,$name:String!,$number:Int!){repository(owner:$owner,name:$name){pullRequest(number:$number){state reviewThreads(first:100){nodes{id isResolved comments(first:10){nodes{databaseId body author{login}}}}}comments(first:100){nodes{databaseId body author{login}}}}}}",
    "variables": {"owner": "tiendv89", "name": "agent-workflow", "number": 38}
  }' | jq '{state: .data.repository.pullRequest.state, threads: [.data.repository.pullRequest.reviewThreads.nodes[] | {id: .id, isResolved: .isResolved, firstComment: .comments.nodes[0].body[:100]}], comments: [.data.repository.pullRequest.comments.nodes[] | {id: .databaseId, body: .body[:100], author: .author.login}]}'

